            results = self._smart_complete(ctx, incomplete)

            if results:
                return results

        return super().shell_complete(ctx, incomplete)

    def _smart_complete(
        self, ctx: Context, incomplete: str
    ) -> list[CompletionItem]:
        """Guess a completion strategy from the option's name and return
        matching completions for the incomplete value. Returns an empty
        list if no pattern matches, so callers can fall back to the
        type's own completion.
