        if "branch" in names:
            return self._complete_git_branches(incomplete)

        if "user" in names:
            return self._complete_usernames(incomplete)

        if "file" in names or "path" in names:
            from click.shell_completion import CompletionItem

            return [CompletionItem(incomplete, type="file")]

        return []

